function waitForCompleteLoad() {
    return new Promise((resolve) => {
        if (document.readyState === 'complete') {
            resolve();
            return;
        }

        const checkLoad = () => {
            if (document.readyState === 'complete') {
                resolve();
            } else {
                setTimeout(checkLoad, 100);
            }
        };

        checkLoad();
    });
}

