// Speed control for streaming video (e.g. Prime Video)
// Run this snippet after the video has loaded.
//
// Usage:
//   - Press D to increase speed by 0.1
//   - Press S to decrease speed by 0.1
//   - Use ss(rate) in the console to set a specific speed
//     Examples: ss(1.7), ss(2), ss(1) to reset to normal
//
// A temporary overlay in the top-left corner shows the current speed
// for 2 seconds whenever it changes.
// The X-Ray panel is automatically removed on run.

// --- Remove X-Ray overlay ---
// Removes the Prime Video X-Ray cast/trivia panel from the DOM entirely.
// document.querySelectorAll('.xrayQuickView, .xrayQuickViewList, [class*="xray"]').forEach(el => el.remove());

// --- Track current rate ourselves to avoid floating point issues ---
let currentRate = 1.0;

// --- Overlay setup ---
// Creates a fixed overlay element in the top-left corner of the page.
// Hidden by default; shown briefly whenever the speed changes.
const overlay = document.createElement('div');
Object.assign(overlay.style, {
  position: 'fixed',
  top: '20px',
  left: '20px',
  background: 'rgba(0, 0, 0, 0.7)',
  color: 'white',
  padding: '8px 14px',
  borderRadius: '6px',
  fontSize: '16px',
  fontFamily: 'monospace',
  zIndex: '999999',
  opacity: '0',
  transition: 'opacity 0.3s ease',
  pointerEvents: 'none', // don't interfere with clicks
});
document.body.appendChild(overlay);

// Timer reference for hiding the overlay after 2 seconds
let overlayTimeout = null;

// --- Show overlay briefly ---
// Displays the current speed in the overlay, then fades it out after 2 seconds.
function showOverlay(text) {
  overlay.textContent = text;
  overlay.style.opacity = '1';
  clearTimeout(overlayTimeout);
  overlayTimeout = setTimeout(() => {
    overlay.style.opacity = '0';
  }, 2000);
}

// --- Set speed ---
// Sets playback rate on all video elements and shows the overlay.
// Updates our internal tracker to avoid floating point drift.
function ss(rate) {
  // Clamp speed to a reasonable range (0.1 to 16)
  rate = Math.min(16, Math.max(0.1, rate));
  // Round to 1 decimal place to avoid floating point drift
  rate = Math.round(rate * 10) / 10;
  currentRate = rate;
  document.querySelectorAll('video').forEach(v => v.playbackRate = rate);
  showOverlay(`${rate.toFixed(1)}x`);
  console.log(`Speed set to ${rate}x`);
}

// --- Keyboard shortcuts ---
// Listens for 'S' (decrease by 0.1) and 'D' (increase by 0.1).
// Ignored when typing in input fields, textareas, etc.
document.addEventListener('keydown', (e) => {
  // Don't trigger when typing in input fields or textareas
  const tag = e.target.tagName.toLowerCase();
  if (tag === 'input' || tag === 'textarea' || e.target.isContentEditable) return;

  if (e.key === 'd' || e.key === 'D') {
    ss(currentRate + 0.1);
  } else if (e.key === 's' || e.key === 'S') {
    ss(currentRate - 0.1);
  }
});

// Set default speed on run
ss(1.0);

// =============================================================================
// Google AI Studio Chat Exporter — DevTools Snippet v5
// =============================================================================
// Fixed: lists, tables, inline code — handles ms-cmark-node wrappers
// CSP/TrustedTypes safe. Per-turn scrolling for virtual scroll.
// =============================================================================

(async () => {
    'use strict';

    const CONFIG = {
      scrollDelayMs: 400,
      exportFormat: 'both',     // 'markdown', 'json', or 'both'
      includeThinking: true,
      includeSystemPrompt: true,
    };

    const sleep = ms => new Promise(r => setTimeout(r, ms));
    const sanitizeFilename = str =>
      str.replace(/[^a-z0-9_\-\s]/gi, '').replace(/\s+/g, '_').substring(0, 80);

    const downloadFile = (content, filename, mimeType = 'text/plain') => {
      const blob = new Blob([content], { type: mimeType });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    };

    // ── CSP-safe status overlay ────────────────────────────────────────────────
    const overlay = document.createElement('div');
    Object.assign(overlay.style, {
      position: 'fixed', top: '16px', right: '16px', zIndex: '999999',
      background: '#1a1a2e', color: '#e0e0e0', padding: '16px 24px',
      borderRadius: '12px', fontFamily: 'system-ui, sans-serif', fontSize: '14px',
      boxShadow: '0 4px 24px rgba(0,0,0,0.4)', minWidth: '300px',
      border: '1px solid #333'
    });
    const hdr = document.createElement('div');
    Object.assign(hdr.style, { fontWeight: '600', marginBottom: '8px', color: '#7c9cff' });
    hdr.textContent = '📦 AI Studio Exporter v5';
    const statusEl = document.createElement('div');
    statusEl.textContent = 'Initializing...';
    const progressEl = document.createElement('div');
    Object.assign(progressEl.style, { marginTop: '6px', fontSize: '12px', color: '#888' });
    overlay.appendChild(hdr);
    overlay.appendChild(statusEl);
    overlay.appendChild(progressEl);
    document.body.appendChild(overlay);

    const setStatus = (msg, detail = '') => {
      statusEl.textContent = msg;
      progressEl.textContent = detail;
      console.log('[Exporter] ' + msg + (detail ? ' — ' + detail : ''));
    };

    // ══════════════════════════════════════════════════════════════════════════
    // ── HTML-to-Markdown converter ──────────────────────────────────────────
    // ══════════════════════════════════════════════════════════════════════════
    //
    // AI Studio DOM pattern:
    //   <ul> → <ms-cmark-node> → <li> → <ms-cmark-node> → <p> → <ms-cmark-node> → text
    //   <table> → <ms-cmark-node> → <tr> → <ms-cmark-node> → <td> → ...
    //   Inline code uses <span class="inline-code"> not <code>
    //
    // Strategy: ms-cmark-node is always transparent (pass-through).
    // All standard HTML tags are converted normally.

    const htmlToMarkdown = (rootEl) => {
      const root = rootEl.cloneNode(true);

      // Remove UI chrome
      root.querySelectorAll(
        'ms-chat-turn-options, button, mat-icon, ' +
        '[aria-label="Copy"], [aria-label="Edit"], ' +
        '.action-buttons, .feedback-buttons, [class*="thumb"], ' +
        '[class*="copy-button"], .overflow-menu, .edit-button, ' +
        '.turn-role-label, .role-label'
      ).forEach(n => n.remove());

      const convert = (node) => {
        // Text node
        if (node.nodeType === Node.TEXT_NODE) {
          return node.textContent || '';
        }
        if (node.nodeType !== Node.ELEMENT_NODE) return '';

        const tag = node.tagName.toLowerCase();

        // ── Transparent wrappers: ms-cmark-node, div.table-container ──
        if (tag === 'ms-cmark-node' || tag === 'ms-text-chunk' || tag === 'ms-prompt-chunk') {
          return Array.from(node.childNodes).map(convert).join('');
        }

        const children = () => Array.from(node.childNodes).map(convert).join('');

        // ── Headings (h1 through h6) ──
        if (tag === 'h1' || tag === 'h2' || tag === 'h3' ||
            tag === 'h4' || tag === 'h5' || tag === 'h6') {
          const level = parseInt(tag.charAt(1));
          return '\n\n' + '#'.repeat(level) + ' ' + children().trim() + '\n\n';
        }

        // ── Paragraphs ──
        if (tag === 'p') {
          const text = children().trim();
          if (!text) return '';
          return '\n\n' + text + '\n\n';
        }

        // ── Line breaks ──
        if (tag === 'br') return '\n';

        // ── Horizontal rules ──
        if (tag === 'hr') return '\n\n---\n\n';

        // ── Blockquotes ──
        if (tag === 'blockquote') {
          const lines = children().trim().split('\n');
          return '\n\n' + lines.map(l => '> ' + l).join('\n') + '\n\n';
        }

        // ── Code blocks: <pre> ──
        if (tag === 'pre') {
          const codeEl = node.querySelector('code');
          const codeText = codeEl ? codeEl.textContent : node.textContent;
          const langClass = (codeEl || node).className.match(/language-(\w+)/);
          const lang = langClass ? langClass[1] :
            (node.getAttribute('data-lang') || node.getAttribute('language') || '');
          return '\n\n```' + lang + '\n' + codeText.trimEnd() + '\n```\n\n';
        }

        // ── Unordered lists ──
        // Children may be <li> directly OR wrapped in <ms-cmark-node>
        if (tag === 'ul') {
          const items = node.querySelectorAll(':scope > li, :scope > ms-cmark-node > li');
          const result = Array.from(items).map(li => {
            const content = convert(li).trim();
            // Indent continuation lines for nested content
            const lines = content.split('\n');
            return '- ' + lines[0] + (lines.length > 1 ? '\n' + lines.slice(1).map(l => '  ' + l).join('\n') : '');
          });
          return '\n\n' + result.join('\n') + '\n\n';
        }

        // ── Ordered lists ──
        if (tag === 'ol') {
          const start = parseInt(node.getAttribute('start') || '1');
          const items = node.querySelectorAll(':scope > li, :scope > ms-cmark-node > li');
          const result = Array.from(items).map((li, i) => {
            const content = convert(li).trim();
            const num = (start + i) + '. ';
            const pad = ' '.repeat(num.length);
            const lines = content.split('\n');
            return num + lines[0] + (lines.length > 1 ? '\n' + lines.slice(1).map(l => pad + l).join('\n') : '');
          });
          return '\n\n' + result.join('\n') + '\n\n';
        }

        // ── List items ──
        if (tag === 'li') {
          return children();
        }

        // ── Tables ──
        if (tag === 'table') {
          const rows = [];
          // Find <tr> elements — may be nested inside ms-cmark-node
          const trEls = node.querySelectorAll('tr');
          trEls.forEach(tr => {
            const cells = tr.querySelectorAll('td, th');
            const rowData = Array.from(cells).map(cell =>
              convert(cell).trim().replace(/\|/g, '\\|').replace(/\n+/g, ' ')
            );
            rows.push(rowData);
          });
          if (rows.length === 0) return children();

          const colCount = Math.max(...rows.map(r => r.length));
          const pad = row => { while (row.length < colCount) row.push(''); return row; };
          const mdRows = rows.map(r => '| ' + pad(r).join(' | ') + ' |');
          if (mdRows.length > 0) {
            mdRows.splice(1, 0, '| ' + Array(colCount).fill('---').join(' | ') + ' |');
          }
          return '\n\n' + mdRows.join('\n') + '\n\n';
        }

        // Table cells — just return content
        if (tag === 'td' || tag === 'th') return children();
        if (tag === 'tr') return children();
        if (tag === 'thead' || tag === 'tbody' || tag === 'tfoot') return children();

        // ── Bold ──
        if (tag === 'strong' || tag === 'b') {
          const t = children().trim();
          return t ? '**' + t + '**' : '';
        }

        // ── Italic ──
        if (tag === 'em' || tag === 'i') {
          const t = children().trim();
          return t ? '*' + t + '*' : '';
        }

        // ── Strikethrough ──
        if (tag === 's' || tag === 'del' || tag === 'strike') {
          return '~~' + children().trim() + '~~';
        }

        // ── Inline code: <code> or <span class="inline-code"> ──
        if (tag === 'code') {
          if (node.parentElement && node.parentElement.tagName.toLowerCase() === 'pre') {
            return node.textContent;
          }
          return '`' + node.textContent + '`';
        }

        // AI Studio uses <span class="inline-code"> for inline code
        if (tag === 'span' && node.classList.contains('inline-code')) {
          return '`' + node.textContent + '`';
        }

        // ── Links ──
        if (tag === 'a') {
          const href = node.getAttribute('href') || '';
          const text = children().trim();
          return href && text ? '[' + text + '](' + href + ')' : text;
        }

        // ── Images ──
        if (tag === 'img') {
          const alt = node.getAttribute('alt') || 'image';
          const src = node.getAttribute('src') || '';
          // Replace the Gemini thinking spinner with a local copy
          if (src.includes('watermark/watermark.png') || node.classList.contains('thinking-progress-icon')) {
            return '![Thinking](watermark.png)';
          }
          if (src) return '![' + alt + '](' + src + ')';
          return '';
        }

        // ── Containers / generic elements — pass through ──
        if (tag === 'div' || tag === 'section' || tag === 'article' ||
            tag === 'main' || tag === 'span' || tag === 'figure' ||
            tag === 'figcaption' || tag === 'details' || tag === 'summary') {
          return children();
        }

        // Default: pass through children
        return children();
      };

      let md = convert(root);
      md = md.replace(/\n{3,}/g, '\n\n');
      return md.trim();
    };

    // ══════════════════════════════════════════════════════════════════════════
    // ── Turn extraction ─────────────────────────────────────────────────────
    // ══════════════════════════════════════════════════════════════════════════

    const findScroller = () => {
      const auto = document.querySelector('ms-autoscroll-container');
      if (auto && auto.scrollHeight > auto.clientHeight) return auto;
      const firstTurn = document.querySelector('ms-chat-turn');
      if (firstTurn) {
        let el = firstTurn.parentElement;
        while (el && el !== document.body) {
          const s = getComputedStyle(el);
          if (/(auto|scroll)/.test(s.overflow + s.overflowY) && el.scrollHeight > el.clientHeight) return el;
          el = el.parentElement;
        }
      }
      return document.documentElement;
    };

    const getTitle = () => {
      const el = document.querySelector('span.title-input, [aria-label="prompt title"]');
      if (el) { const v = (el.value || el.textContent || '').trim(); if (v) return v; }
      return document.title.replace(/ [-|] Google AI Studio.*/, '').trim() || 'AI_Studio_Export';
    };

    const getSystemPrompt = () => {
      if (!CONFIG.includeSystemPrompt) return '';
      for (const sel of [
        'ms-system-instructions-panel textarea',
        'textarea[aria-label*="system" i]',
      ]) {
        const el = document.querySelector(sel);
        if (el && el.value && el.value.trim()) return el.value.trim();
      }
      return '';
    };

    const extractSingleTurn = (turn) => {
      // ── Role ──
      let role = 'unknown';
      const rc = turn.querySelector('[data-turn-role]');
      if (rc) {
        const r = rc.getAttribute('data-turn-role').toLowerCase();
        if (r === 'user') role = 'user'; else if (r === 'model') role = 'model';
      }
      if (role === 'unknown') {
        const c = turn.querySelector('.chat-turn-container');
        if (c) { if (c.classList.contains('user')) role = 'user'; else if (c.classList.contains('model')) role = 'model'; }
      }

      // ── Thinking ──
      let thinking = '';
      if (CONFIG.includeThinking) {
        // Thinking content lives inside: ms-thought-chunk → mat-accordion →
        //   mat-expansion-panel.thought-panel → ... → ms-text-chunk → ms-cmark-node.cmark-node
        const thoughtChunk = turn.querySelector('ms-thought-chunk');
        if (thoughtChunk) {
          const thoughtPanel = thoughtChunk.querySelector('mat-expansion-panel.thought-panel');
          if (thoughtPanel) {
            const cmarkRoot = thoughtPanel.querySelector('ms-cmark-node.cmark-node');
            if (cmarkRoot) {
              thinking = htmlToMarkdown(cmarkRoot);
            } else {
              const body = thoughtPanel.querySelector('.mat-expansion-panel-body');
              if (body) thinking = htmlToMarkdown(body);
            }
          }
        }
      }

      // ── Main content ──
      let content = '';

      // The main content is the ms-text-chunk that is a DIRECT child of text-chunk,
      // NOT the one inside ms-thought-chunk.
      const textChunkContainer = turn.querySelector('ms-prompt-chunk.text-chunk');
      if (textChunkContainer) {
        // Get all ms-text-chunk children, but skip the one inside ms-thought-chunk
        const allTextChunks = textChunkContainer.querySelectorAll(':scope > ms-text-chunk');
        for (const tc of allTextChunks) {
          const cmarkRoot = tc.querySelector('ms-cmark-node.cmark-node');
          if (cmarkRoot) {
            content = htmlToMarkdown(cmarkRoot);
            break;
          }
        }
        // If no direct ms-text-chunk found (maybe thinking is in the way),
        // look for ms-text-chunk that is NOT inside ms-thought-chunk
        if (!content) {
          const allTC = textChunkContainer.querySelectorAll('ms-text-chunk');
          for (const tc of allTC) {
            if (tc.closest('ms-thought-chunk')) continue; // skip thinking
            const cmarkRoot = tc.querySelector('ms-cmark-node.cmark-node');
            if (cmarkRoot) { content = htmlToMarkdown(cmarkRoot); break; }
          }
        }
      }

      // Fallback
      if (!content) {
        const turnContent = turn.querySelector('.turn-content');
        if (turnContent) content = htmlToMarkdown(turnContent);
      }
      if (!content) content = htmlToMarkdown(turn);

      // Clean role prefix
      content = content.replace(/^\s*(User|Model)\s*\n/, '').trim();

      return { role, content, thinking: thinking || undefined };
    };

    // ══════════════════════════════════════════════════════════════════════════
    // ── Main ────────────────────────────────────────────────────────────────
    // ══════════════════════════════════════════════════════════════════════════
    try {
      if (!window.location.hostname.includes('aistudio.google.com')) {
        setStatus('⚠️ Not on Google AI Studio!');
        await sleep(3000); overlay.remove(); return;
      }

      const title = getTitle();
      setStatus('Exporting: ' + title);
      const scroller = findScroller();

      // Phase 1: Scroll to load all turns
      setStatus('Scrolling to load all turns...');
      scroller.scrollTop = 0;
      await sleep(300);
      let lastH = -1, stable = 0;
      for (let i = 0; i < 200; i++) {
        scroller.scrollTop = scroller.scrollHeight;
        await sleep(200);
        if (scroller.scrollHeight === lastH) { if (++stable >= 4) break; }
        else stable = 0;
        lastH = scroller.scrollHeight;
      }

      const totalTurns = document.querySelectorAll('ms-chat-turn').length;
      setStatus('Found ' + totalTurns + ' turns. Extracting...');

      // Phase 2: Per-turn extraction
      const messages = [];
      for (let i = 0; i < totalTurns; i++) {
        let turn = document.querySelectorAll('ms-chat-turn')[i];
        if (!turn) continue;
        turn.scrollIntoView({ behavior: 'instant', block: 'center' });
        await sleep(CONFIG.scrollDelayMs);

        turn = document.querySelectorAll('ms-chat-turn')[i];
        if (!turn) continue;

        // Expand thinking panels
        turn.querySelectorAll('mat-expansion-panel.thought-panel').forEach(tp => {
          if (!tp.classList.contains('mat-expanded')) {
            const h = tp.querySelector('mat-expansion-panel-header');
            if (h) try { h.click(); } catch (e) {}
          }
        });
        await sleep(200);

        // Re-query after expansion
        turn = document.querySelectorAll('ms-chat-turn')[i];
        const data = extractSingleTurn(turn);
        data.turnIndex = i;

        setStatus('Extracting...', 'Turn ' + (i + 1) + '/' + totalTurns +
          ' (' + data.role + ', ' + data.content.length + ' chars)');

        if (data.content || data.thinking) messages.push(data);
        else console.warn('[Exporter] Turn ' + i + ' — empty');
      }

      if (messages.length === 0) {
        setStatus('⚠️ No content!'); await sleep(4000); overlay.remove(); return;
      }

      // Phase 3: System prompt
      const systemPrompt = getSystemPrompt();

      // Phase 4: Download
      setStatus('Generating files...');
      const safeName = sanitizeFilename(title) || 'export';
      const ts = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
      const base = safeName + '_' + ts;

      if (CONFIG.exportFormat === 'markdown' || CONFIG.exportFormat === 'both') {
        const md = [];
        md.push('# ' + title);
        md.push('');
        md.push('> Exported from Google AI Studio on ' + new Date().toISOString());
        md.push('> Source: ' + window.location.href);
        md.push('');
        if (systemPrompt) {
          md.push('## System Instructions');
          md.push('');
          md.push('```');
          md.push(systemPrompt);
          md.push('```');
          md.push('');
        }
        md.push('---');
        md.push('');
        messages.forEach(msg => {
          md.push(msg.role === 'user' ? '## 👤 User' : '## 🤖 Model');
          md.push('');
          if (msg.thinking) {
            md.push('<details>');
            md.push('<summary>💭 Thinking / Reasoning</summary>');
            md.push('');
            md.push(msg.thinking);
            md.push('');
            md.push('</details>');
            md.push('');
          }
          md.push(msg.content);
          md.push('');
          md.push('---');
          md.push('');
        });
        downloadFile(md.join('\n'), base + '.md', 'text/markdown');
      }

      if (CONFIG.exportFormat === 'json' || CONFIG.exportFormat === 'both') {
        downloadFile(JSON.stringify({
          title,
          exported_at: new Date().toISOString(),
          source: window.location.href,
          system_instruction: systemPrompt || undefined,
          turn_count: messages.length,
          messages: messages.map(m => ({
            role: m.role, content: m.content,
            ...(m.thinking ? { thinking: m.thinking } : {}),
          }))
        }, null, 2), base + '.json', 'application/json');
      }

      setStatus('✅ Done! ' + messages.length + '/' + totalTurns + ' turns exported.', base + '.*');
      await sleep(5000);
    } catch (err) {
      setStatus('❌ ' + err.message);
      console.error('[Exporter]', err);
      await sleep(5000);
    } finally {
      overlay.remove();
    }
  })();

// =============================================================================
// Google AI Studio Chat Exporter — DevTools Snippet v6
// =============================================================================
// - Converts rendered HTML back to proper Markdown
// - Handles ms-cmark-node wrappers for lists, tables, inline code
// - Extracts base64 images as separate files, references by filename
// - Per-turn scrolling to defeat virtual scrolling
// - CSP/TrustedTypes safe
// =============================================================================

(async () => {
    'use strict';

    const CONFIG = {
      scrollDelayMs: 400,
      exportFormat: 'both',     // 'markdown', 'json', or 'both'
      includeThinking: true,
      includeSystemPrompt: true,
      extractImages: true,      // save base64 images as separate files
    };

    const sleep = ms => new Promise(r => setTimeout(r, ms));
    const sanitizeFilename = str =>
      str.replace(/[^a-z0-9_\-\s]/gi, '').replace(/\s+/g, '_').substring(0, 80);

    const downloadFile = (content, filename, mimeType = 'text/plain') => {
      const blob = new Blob([content], { type: mimeType });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    };

    const downloadBlob = (blob, filename) => {
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    };

    // ── CSP-safe status overlay ────────────────────────────────────────────────
    const overlay = document.createElement('div');
    Object.assign(overlay.style, {
      position: 'fixed', top: '16px', right: '16px', zIndex: '999999',
      background: '#1a1a2e', color: '#e0e0e0', padding: '16px 24px',
      borderRadius: '12px', fontFamily: 'system-ui, sans-serif', fontSize: '14px',
      boxShadow: '0 4px 24px rgba(0,0,0,0.4)', minWidth: '300px',
      border: '1px solid #333'
    });
    const hdr = document.createElement('div');
    Object.assign(hdr.style, { fontWeight: '600', marginBottom: '8px', color: '#7c9cff' });
    hdr.textContent = '📦 AI Studio Exporter v6';
    const statusEl = document.createElement('div');
    statusEl.textContent = 'Initializing...';
    const progressEl = document.createElement('div');
    Object.assign(progressEl.style, { marginTop: '6px', fontSize: '12px', color: '#888' });
    overlay.appendChild(hdr);
    overlay.appendChild(statusEl);
    overlay.appendChild(progressEl);
    document.body.appendChild(overlay);

    const setStatus = (msg, detail = '') => {
      statusEl.textContent = msg;
      progressEl.textContent = detail;
      console.log('[Exporter] ' + msg + (detail ? ' — ' + detail : ''));
    };

    // ══════════════════════════════════════════════════════════════════════════
    // ── Image collector ─────────────────────────────────────────────────────
    // ══════════════════════════════════════════════════════════════════════════

    // Stores { originalSrc, filename, mimeType, base64data } for deferred download
    const collectedImages = [];
    let imageCounter = 0;

    const base64ToBlob = (b64, mimeType) => {
      const byteChars = atob(b64);
      const byteArr = new Uint8Array(byteChars.length);
      for (let i = 0; i < byteChars.length; i++) byteArr[i] = byteChars.charCodeAt(i);
      return new Blob([byteArr], { type: mimeType });
    };

    const getImageFilename = (src, alt) => {
      // Try to derive a meaningful name from the alt text
      let name = (alt || '').replace(/[^a-z0-9_\-\s.]/gi, '').replace(/\s+/g, '_').substring(0, 60);
      if (!name || name === 'image') name = 'image_' + (++imageCounter);
      else imageCounter++;

      // Determine extension from mime or src
      let ext = 'png';
      if (src.includes('data:image/jpeg') || src.includes('data:image/jpg')) ext = 'jpg';
      else if (src.includes('data:image/gif')) ext = 'gif';
      else if (src.includes('data:image/webp')) ext = 'webp';
      else if (src.includes('data:image/svg')) ext = 'svg';

      // Avoid duplicate extensions
      if (!name.endsWith('.' + ext)) name += '.' + ext;
      return name;
    };

    // ══════════════════════════════════════════════════════════════════════════
    // ── HTML-to-Markdown converter ──────────────────────────────────────────
    // ══════════════════════════════════════════════════════════════════════════

    const htmlToMarkdown = (rootEl) => {
      const root = rootEl.cloneNode(true);

      // Remove UI chrome
      root.querySelectorAll(
        'ms-chat-turn-options, button, mat-icon, ' +
        '[aria-label="Copy"], [aria-label="Edit"], ' +
        '.action-buttons, .feedback-buttons, [class*="thumb"], ' +
        '[class*="copy-button"], .overflow-menu, .edit-button, ' +
        '.turn-role-label, .role-label'
      ).forEach(n => n.remove());

      const convert = (node) => {
        if (node.nodeType === Node.TEXT_NODE) return node.textContent || '';
        if (node.nodeType !== Node.ELEMENT_NODE) return '';

        const tag = node.tagName.toLowerCase();

        // ── Transparent wrappers ──
        if (tag === 'ms-cmark-node' || tag === 'ms-text-chunk' || tag === 'ms-prompt-chunk') {
          return Array.from(node.childNodes).map(convert).join('');
        }

        const children = () => Array.from(node.childNodes).map(convert).join('');

        // ── Headings h1–h6 ──
        if (tag === 'h1' || tag === 'h2' || tag === 'h3' ||
            tag === 'h4' || tag === 'h5' || tag === 'h6') {
          const level = parseInt(tag.charAt(1));
          return '\n\n' + '#'.repeat(level) + ' ' + children().trim() + '\n\n';
        }

        // ── Paragraphs ──
        if (tag === 'p') {
          const text = children().trim();
          return text ? '\n\n' + text + '\n\n' : '';
        }

        if (tag === 'br') return '\n';
        if (tag === 'hr') return '\n\n---\n\n';

        // ── Blockquotes ──
        if (tag === 'blockquote') {
          return '\n\n' + children().trim().split('\n').map(l => '> ' + l).join('\n') + '\n\n';
        }

        // ── Code blocks ──
        if (tag === 'pre') {
          const codeEl = node.querySelector('code');
          const codeText = codeEl ? codeEl.textContent : node.textContent;
          const langClass = (codeEl || node).className.match(/language-(\w+)/);
          const lang = langClass ? langClass[1] :
            (node.getAttribute('data-lang') || node.getAttribute('language') || '');
          return '\n\n```' + lang + '\n' + codeText.trimEnd() + '\n```\n\n';
        }

        // ── Unordered lists (handles ms-cmark-node wrappers) ──
        if (tag === 'ul') {
          const items = node.querySelectorAll(':scope > li, :scope > ms-cmark-node > li');
          const result = Array.from(items).map(li => {
            const c = convert(li).trim();
            const lines = c.split('\n');
            return '- ' + lines[0] + (lines.length > 1 ? '\n' + lines.slice(1).map(l => '  ' + l).join('\n') : '');
          });
          return '\n\n' + result.join('\n') + '\n\n';
        }

        // ── Ordered lists ──
        if (tag === 'ol') {
          const start = parseInt(node.getAttribute('start') || '1');
          const items = node.querySelectorAll(':scope > li, :scope > ms-cmark-node > li');
          const result = Array.from(items).map((li, i) => {
            const c = convert(li).trim();
            const num = (start + i) + '. ';
            const pad = ' '.repeat(num.length);
            const lines = c.split('\n');
            return num + lines[0] + (lines.length > 1 ? '\n' + lines.slice(1).map(l => pad + l).join('\n') : '');
          });
          return '\n\n' + result.join('\n') + '\n\n';
        }

        if (tag === 'li') return children();

        // ── Tables (handles ms-cmark-node wrappers) ──
        if (tag === 'table') {
          const rows = [];
          node.querySelectorAll('tr').forEach(tr => {
            const cells = tr.querySelectorAll('td, th');
            rows.push(Array.from(cells).map(cell =>
              convert(cell).trim().replace(/\|/g, '\\|').replace(/\n+/g, ' ')
            ));
          });
          if (rows.length === 0) return children();
          const colCount = Math.max(...rows.map(r => r.length));
          const pad = row => { while (row.length < colCount) row.push(''); return row; };
          const mdRows = rows.map(r => '| ' + pad(r).join(' | ') + ' |');
          if (mdRows.length > 0) mdRows.splice(1, 0, '| ' + Array(colCount).fill('---').join(' | ') + ' |');
          return '\n\n' + mdRows.join('\n') + '\n\n';
        }

        if (tag === 'td' || tag === 'th' || tag === 'tr' ||
            tag === 'thead' || tag === 'tbody' || tag === 'tfoot') return children();

        // ── Bold ──
        if (tag === 'strong' || tag === 'b') {
          const t = children().trim();
          return t ? '**' + t + '**' : '';
        }

        // ── Italic ──
        if (tag === 'em' || tag === 'i') {
          const t = children().trim();
          return t ? '*' + t + '*' : '';
        }

        // ── Strikethrough ──
        if (tag === 's' || tag === 'del' || tag === 'strike') {
          return '~~' + children().trim() + '~~';
        }

        // ── Inline code: <code> or <span class="inline-code"> ──
        if (tag === 'code') {
          if (node.parentElement && node.parentElement.tagName.toLowerCase() === 'pre') return node.textContent;
          return '`' + node.textContent + '`';
        }
        if (tag === 'span' && node.classList.contains('inline-code')) {
          return '`' + node.textContent + '`';
        }

        // ── Links ──
        if (tag === 'a') {
          const href = node.getAttribute('href') || '';
          const text = children().trim();
          return href && text ? '[' + text + '](' + href + ')' : text;
        }

        // ── Images ──
        if (tag === 'img') {
          const alt = node.getAttribute('alt') || 'image';
          const src = node.getAttribute('src') || '';

          // Thinking spinner → local reference
          if (src.includes('watermark/watermark.png') || node.classList.contains('thinking-progress-icon')) {
            return '![Thinking](watermark.png)';
          }

          // Base64 embedded image → extract to separate file
          if (CONFIG.extractImages && src.startsWith('data:image/')) {
            const filename = getImageFilename(src, alt);
            const commaIdx = src.indexOf(',');
            if (commaIdx !== -1) {
              const mimeMatch = src.match(/^data:(image\/[^;]+)/);
              const mimeType = mimeMatch ? mimeMatch[1] : 'image/png';
              const b64 = src.substring(commaIdx + 1);
              collectedImages.push({ filename, mimeType, base64data: b64 });
            }
            return '![' + alt + '](' + filename + ')';
          }

          if (src) return '![' + alt + '](' + src + ')';
          return '';
        }

        // ── Containers — pass through ──
        if (tag === 'div' || tag === 'section' || tag === 'article' ||
            tag === 'main' || tag === 'span' || tag === 'figure' ||
            tag === 'figcaption' || tag === 'details' || tag === 'summary') {
          return children();
        }

        return children();
      };

      let md = convert(root);
      md = md.replace(/\n{3,}/g, '\n\n');
      return md.trim();
    };

    // ══════════════════════════════════════════════════════════════════════════
    // ── Turn extraction ─────────────────────────────────────────────────────
    // ══════════════════════════════════════════════════════════════════════════

    const findScroller = () => {
      const auto = document.querySelector('ms-autoscroll-container');
      if (auto && auto.scrollHeight > auto.clientHeight) return auto;
      const ft = document.querySelector('ms-chat-turn');
      if (ft) {
        let el = ft.parentElement;
        while (el && el !== document.body) {
          const s = getComputedStyle(el);
          if (/(auto|scroll)/.test(s.overflow + s.overflowY) && el.scrollHeight > el.clientHeight) return el;
          el = el.parentElement;
        }
      }
      return document.documentElement;
    };

    const getTitle = () => {
      const el = document.querySelector('span.title-input, [aria-label="prompt title"]');
      if (el) { const v = (el.value || el.textContent || '').trim(); if (v) return v; }
      return document.title.replace(/ [-|] Google AI Studio.*/, '').trim() || 'AI_Studio_Export';
    };

    const getSystemPrompt = () => {
      if (!CONFIG.includeSystemPrompt) return '';
      for (const sel of [
        'ms-system-instructions-panel textarea',
        'textarea[aria-label*="system" i]',
      ]) {
        const el = document.querySelector(sel);
        if (el && el.value && el.value.trim()) return el.value.trim();
      }
      return '';
    };

    const extractSingleTurn = (turn) => {
      // ── Role ──
      let role = 'unknown';
      const rc = turn.querySelector('[data-turn-role]');
      if (rc) {
        const r = rc.getAttribute('data-turn-role').toLowerCase();
        if (r === 'user') role = 'user'; else if (r === 'model') role = 'model';
      }
      if (role === 'unknown') {
        const c = turn.querySelector('.chat-turn-container');
        if (c) { if (c.classList.contains('user')) role = 'user'; else if (c.classList.contains('model')) role = 'model'; }
      }

      // ── Thinking ──
      let thinking = '';
      if (CONFIG.includeThinking) {
        const thoughtChunk = turn.querySelector('ms-thought-chunk');
        if (thoughtChunk) {
          const tp = thoughtChunk.querySelector('mat-expansion-panel.thought-panel');
          if (tp) {
            const cr = tp.querySelector('ms-cmark-node.cmark-node');
            if (cr) thinking = htmlToMarkdown(cr);
            else {
              const body = tp.querySelector('.mat-expansion-panel-body');
              if (body) thinking = htmlToMarkdown(body);
            }
          }
        }
      }

      // ── Main text content ──
      let content = '';
      const textChunkContainer = turn.querySelector('ms-prompt-chunk.text-chunk');
      if (textChunkContainer) {
        const allTC = textChunkContainer.querySelectorAll('ms-text-chunk');
        for (const tc of allTC) {
          if (tc.closest('ms-thought-chunk')) continue;
          const cr = tc.querySelector('ms-cmark-node.cmark-node');
          if (cr) { content = htmlToMarkdown(cr); break; }
        }
      }
      if (!content) {
        const tc = turn.querySelector('.turn-content');
        if (tc) content = htmlToMarkdown(tc);
      }
      if (!content) content = htmlToMarkdown(turn);

      content = content.replace(/^\s*(User|Model)\s*\n/, '').trim();

      // ── Collect images from ALL ms-image-chunk elements in this turn ──
      // These live in ms-prompt-chunk (without .text-chunk) → ms-image-chunk → img
      const imageChunks = turn.querySelectorAll('ms-image-chunk img.loaded-image, ms-image-chunk img[src]');
      imageChunks.forEach(img => {
        const src = img.getAttribute('src') || '';
        const alt = img.getAttribute('alt') || 'image';

        // Thinking spinner — skip
        if (src.includes('watermark/watermark.png') || img.classList.contains('thinking-progress-icon')) return;

        if (CONFIG.extractImages && src.startsWith('data:image/')) {
          const filename = getImageFilename(src, alt);
          const commaIdx = src.indexOf(',');
          if (commaIdx !== -1) {
            const mimeMatch = src.match(/^data:(image\/[^;]+)/);
            const mimeType = mimeMatch ? mimeMatch[1] : 'image/png';
            const b64 = src.substring(commaIdx + 1);
            collectedImages.push({ filename, mimeType, base64data: b64 });
          }
          content += (content ? '\n\n' : '') + '![' + alt + '](' + filename + ')';
        } else if (src.startsWith('blob:')) {
          // Blob URLs — attempt to fetch and convert
          const filename = getImageFilename('data:image/png', alt);
          collectedImages.push({ filename, mimeType: 'image/png', blobUrl: src });
          content += (content ? '\n\n' : '') + '![' + alt + '](' + filename + ')';
        } else if (src && !src.includes('watermark')) {
          content += (content ? '\n\n' : '') + '![' + alt + '](' + src + ')';
        }
      });

      return { role, content, thinking: thinking || undefined };
    };

    // ══════════════════════════════════════════════════════════════════════════
    // ── Main ────────────────────────────────────────────────────────────────
    // ══════════════════════════════════════════════════════════════════════════
    try {
      // ── Page validation ──────────────────────────────────────────────────
      const hostname = window.location.hostname;
      const pathname = window.location.pathname;
      const onAIStudio = hostname.includes('aistudio.google.com');
      const promptMatch = pathname.match(/^\/prompts\/([a-zA-Z0-9_\-]+)$/);
      const onPrompt = onAIStudio && promptMatch && promptMatch[1] !== 'new_chat';
      const onLibrary = onAIStudio && pathname === '/library';

      // Helper: build a CSP-safe dialog
      const showDialog = (titleText, messageText, buttons) => {
        overlay.remove();

        const backdrop = document.createElement('div');
        Object.assign(backdrop.style, {
          position: 'fixed', inset: '0', zIndex: '999998',
          background: 'rgba(0,0,0,0.5)', display: 'flex',
          alignItems: 'center', justifyContent: 'center',
        });

        const dialog = document.createElement('div');
        Object.assign(dialog.style, {
          background: '#1a1a2e', color: '#e0e0e0', padding: '28px 32px',
          borderRadius: '14px', fontFamily: 'system-ui, sans-serif', fontSize: '15px',
          boxShadow: '0 8px 32px rgba(0,0,0,0.5)', maxWidth: '440px',
          border: '1px solid #333', textAlign: 'center',
        });

        const hdrEl = document.createElement('div');
        Object.assign(hdrEl.style, { fontWeight: '600', fontSize: '17px', marginBottom: '12px', color: '#7c9cff' });
        hdrEl.textContent = titleText;

        const msgEl = document.createElement('div');
        Object.assign(msgEl.style, { marginBottom: '14px', lineHeight: '1.5' });
        msgEl.textContent = messageText;

        const pathEl = document.createElement('div');
        Object.assign(pathEl.style, { fontSize: '12px', color: '#888', marginBottom: '18px', wordBreak: 'break-all' });
        pathEl.textContent = 'Current: ' + window.location.href;

        const btnRow = document.createElement('div');
        Object.assign(btnRow.style, { display: 'flex', gap: '12px', justifyContent: 'center', flexWrap: 'wrap' });

        buttons.forEach(({ text, primary, action }) => {
          const btn = document.createElement('button');
          btn.textContent = text;
          Object.assign(btn.style, {
            padding: '10px 24px', borderRadius: '8px', border: 'none', cursor: 'pointer',
            fontSize: '14px', fontWeight: '500',
            background: primary ? '#7c9cff' : '#333',
            color: primary ? '#1a1a2e' : '#ccc',
          });
          btn.addEventListener('click', () => { backdrop.remove(); if (action) action(); });
          btnRow.appendChild(btn);
        });

        dialog.appendChild(hdrEl);
        dialog.appendChild(msgEl);
        dialog.appendChild(pathEl);
        dialog.appendChild(btnRow);
        backdrop.appendChild(dialog);
        document.body.appendChild(backdrop);
        backdrop.addEventListener('click', (e) => { if (e.target === backdrop) backdrop.remove(); });
      };

      if (!onAIStudio) {
        showDialog(
          '📦 AI Studio Exporter',
          'This script only works on Google AI Studio. Please navigate to aistudio.google.com and open a chat conversation first.',
          [
            { text: 'Go to AI Studio', primary: true, action: () => { window.location.href = 'https://aistudio.google.com/library'; } },
            { text: 'Cancel', primary: false },
          ]
        );
        return;
      }

      if (onLibrary) {
        showDialog(
          '📦 AI Studio Exporter',
          'You\'re on the Library page. To export a conversation, click on one of your chats in the list below to open it, then run this script again.',
          [
            { text: 'Got it', primary: true },
          ]
        );
        return;
      }

      if (!onPrompt) {
        showDialog(
          '📦 AI Studio Exporter',
          'This page doesn\'t look like a chat conversation. You need to open a specific chat in Google AI Studio first. Would you like to go to your Library to pick one?',
          [
            { text: 'Go to Library', primary: true, action: () => { window.location.href = 'https://aistudio.google.com/library'; } },
            { text: 'Cancel', primary: false },
          ]
        );
        return;
      }

      const title = getTitle();
      setStatus('Exporting: ' + title);
      const scroller = findScroller();

      // Phase 1: Scroll to load all turns
      setStatus('Scrolling to load all turns...');
      scroller.scrollTop = 0; await sleep(300);
      let lastH = -1, stable = 0;
      for (let i = 0; i < 200; i++) {
        scroller.scrollTop = scroller.scrollHeight; await sleep(200);
        if (scroller.scrollHeight === lastH) { if (++stable >= 4) break; }
        else stable = 0;
        lastH = scroller.scrollHeight;
      }

      const totalTurns = document.querySelectorAll('ms-chat-turn').length;
      setStatus('Found ' + totalTurns + ' turns. Extracting...');

      // Phase 2: Per-turn extraction
      const messages = [];
      for (let i = 0; i < totalTurns; i++) {
        let turn = document.querySelectorAll('ms-chat-turn')[i];
        if (!turn) continue;
        turn.scrollIntoView({ behavior: 'instant', block: 'center' });
        await sleep(CONFIG.scrollDelayMs);

        turn = document.querySelectorAll('ms-chat-turn')[i];
        if (!turn) continue;

        // Expand thinking
        turn.querySelectorAll('mat-expansion-panel.thought-panel').forEach(tp => {
          if (!tp.classList.contains('mat-expanded')) {
            const h = tp.querySelector('mat-expansion-panel-header');
            if (h) try { h.click(); } catch (e) {}
          }
        });
        await sleep(200);

        turn = document.querySelectorAll('ms-chat-turn')[i];
        const data = extractSingleTurn(turn);
        data.turnIndex = i;

        setStatus('Extracting...', 'Turn ' + (i + 1) + '/' + totalTurns +
          ' (' + data.role + ', ' + data.content.length + ' chars)');

        if (data.content || data.thinking) messages.push(data);
        else console.warn('[Exporter] Turn ' + i + ' — empty');
      }

      if (messages.length === 0) {
        setStatus('⚠️ No content!'); await sleep(4000); overlay.remove(); return;
      }

      // Phase 3: System prompt
      const systemPrompt = getSystemPrompt();

      // Phase 4: Download
      setStatus('Generating files...');
      const safeName = sanitizeFilename(title) || 'export';
      const ts = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
      const base = safeName + '_' + ts;

      // Markdown
      if (CONFIG.exportFormat === 'markdown' || CONFIG.exportFormat === 'both') {
        const md = [];
        md.push('# ' + title);
        md.push('');
        md.push('> Exported from Google AI Studio on ' + new Date().toISOString());
        md.push('> Source: ' + window.location.href);
        md.push('');
        if (systemPrompt) {
          md.push('## System Instructions');
          md.push('');
          md.push('```');
          md.push(systemPrompt);
          md.push('```');
          md.push('');
        }
        md.push('---');
        md.push('');
        messages.forEach(msg => {
          md.push(msg.role === 'user' ? '## 👤 User' : '## 🤖 Model');
          md.push('');
          if (msg.thinking) {
            md.push('<details>');
            md.push('<summary>💭 Thinking / Reasoning</summary>');
            md.push('');
            md.push(msg.thinking);
            md.push('');
            md.push('</details>');
            md.push('');
          }
          md.push(msg.content);
          md.push('');
          md.push('---');
          md.push('');
        });
        downloadFile(md.join('\n'), base + '.md', 'text/markdown');
      }

      // JSON
      if (CONFIG.exportFormat === 'json' || CONFIG.exportFormat === 'both') {
        downloadFile(JSON.stringify({
          title,
          exported_at: new Date().toISOString(),
          source: window.location.href,
          system_instruction: systemPrompt || undefined,
          turn_count: messages.length,
          images: collectedImages.length > 0
            ? collectedImages.map(img => img.filename)
            : undefined,
          messages: messages.map(m => ({
            role: m.role, content: m.content,
            ...(m.thinking ? { thinking: m.thinking } : {}),
          }))
        }, null, 2), base + '.json', 'application/json');
      }

      // Phase 5: Download extracted images
      if (collectedImages.length > 0) {
        setStatus('Downloading ' + collectedImages.length + ' images...');
        for (let i = 0; i < collectedImages.length; i++) {
          const img = collectedImages[i];
          setStatus('Saving image...', (i + 1) + '/' + collectedImages.length + ': ' + img.filename);
          try {
            let blob;
            if (img.base64data) {
              blob = base64ToBlob(img.base64data, img.mimeType);
            } else if (img.blobUrl) {
              // Fetch the blob URL (works for same-origin blob URLs)
              try {
                const resp = await fetch(img.blobUrl);
                blob = await resp.blob();
              } catch (e) {
                console.warn('[Exporter] Could not fetch blob URL for: ' + img.filename, e);
                continue;
              }
            }
            if (blob) {
              downloadBlob(blob, img.filename);
              await sleep(300); // gap between downloads to avoid browser throttling
            }
          } catch (e) {
            console.warn('[Exporter] Failed to save image: ' + img.filename, e);
          }
        }
      }

      setStatus(
        '✅ Done! ' + messages.length + '/' + totalTurns + ' turns' +
          (collectedImages.length > 0 ? ', ' + collectedImages.length + ' images' : '') + ' exported.',
        base + '.*'
      );
      await sleep(5000);

    } catch (err) {
      setStatus('❌ ' + err.message);
      console.error('[Exporter]', err);
      await sleep(5000);
    } finally {
      overlay.remove();
    }
  })();

// =============================================================================
// AI Studio Library Exporter — DevTools Snippet
// =============================================================================
// Run on: https://aistudio.google.com/library
// Exports all prompts/chats listed on the page as JSON and/or CSV.
// Scrolls the table to capture all entries if virtualized.
// =============================================================================

(async () => {
    'use strict';

    const CONFIG = {
      exportFormat: 'all', // 'json', 'csv', 'markdown', or 'all'
      scrollDelayMs: 300,
    };

    const sleep = ms => new Promise(r => setTimeout(r, ms));

    const downloadFile = (content, filename, mimeType = 'text/plain') => {
      const blob = new Blob([content], { type: mimeType });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    };

    // ── CSP-safe overlay ───────────────────────────────────────────────────────
    const overlay = document.createElement('div');
    Object.assign(overlay.style, {
      position: 'fixed', top: '16px', right: '16px', zIndex: '999999',
      background: '#1a1a2e', color: '#e0e0e0', padding: '16px 24px',
      borderRadius: '12px', fontFamily: 'system-ui, sans-serif', fontSize: '14px',
      boxShadow: '0 4px 24px rgba(0,0,0,0.4)', minWidth: '300px',
      border: '1px solid #333'
    });
    const hdr = document.createElement('div');
    Object.assign(hdr.style, { fontWeight: '600', marginBottom: '8px', color: '#7c9cff' });
    hdr.textContent = '📚 Library Exporter';
    const statusEl = document.createElement('div');
    statusEl.textContent = 'Initializing...';
    const progressEl = document.createElement('div');
    Object.assign(progressEl.style, { marginTop: '6px', fontSize: '12px', color: '#888' });
    overlay.appendChild(hdr);
    overlay.appendChild(statusEl);
    overlay.appendChild(progressEl);
    document.body.appendChild(overlay);

    const setStatus = (msg, detail = '') => {
      statusEl.textContent = msg;
      progressEl.textContent = detail;
      console.log('[LibExporter] ' + msg + (detail ? ' — ' + detail : ''));
    };

    try {
      // ── Verify page ──────────────────────────────────────────────────────
      const onAIStudio = window.location.hostname.includes('aistudio.google.com');
      const onLibrary = onAIStudio && window.location.pathname === '/library';

      if (!onAIStudio) {
        setStatus('⚠️ Not on Google AI Studio!');
        await sleep(3000); overlay.remove(); return;
      }

      if (!onLibrary) {
        overlay.remove(); // hide the status overlay, use a dialog instead

        // Build a CSP-safe dialog
        const backdrop = document.createElement('div');
        Object.assign(backdrop.style, {
          position: 'fixed', inset: '0', zIndex: '999998',
          background: 'rgba(0,0,0,0.5)', display: 'flex',
          alignItems: 'center', justifyContent: 'center',
        });

        const dialog = document.createElement('div');
        Object.assign(dialog.style, {
          background: '#1a1a2e', color: '#e0e0e0', padding: '28px 32px',
          borderRadius: '14px', fontFamily: 'system-ui, sans-serif', fontSize: '15px',
          boxShadow: '0 8px 32px rgba(0,0,0,0.5)', maxWidth: '420px',
          border: '1px solid #333', textAlign: 'center',
        });

        const title = document.createElement('div');
        Object.assign(title.style, { fontWeight: '600', fontSize: '17px', marginBottom: '12px', color: '#7c9cff' });
        title.textContent = '📚 Library Exporter';

        const msg = document.createElement('div');
        Object.assign(msg.style, { marginBottom: '20px', lineHeight: '1.5' });
        msg.textContent = 'This script needs to run on the Library page. You are currently on a different page. Would you like to go to the Library page now?';

        const currentPage = document.createElement('div');
        Object.assign(currentPage.style, { fontSize: '12px', color: '#888', marginBottom: '18px', wordBreak: 'break-all' });
        currentPage.textContent = 'Current: ' + window.location.pathname;

        const btnRow = document.createElement('div');
        Object.assign(btnRow.style, { display: 'flex', gap: '12px', justifyContent: 'center' });

        const makeBtn = (text, primary) => {
          const btn = document.createElement('button');
          btn.textContent = text;
          Object.assign(btn.style, {
            padding: '10px 24px', borderRadius: '8px', border: 'none', cursor: 'pointer',
            fontSize: '14px', fontWeight: '500',
            background: primary ? '#7c9cff' : '#333',
            color: primary ? '#1a1a2e' : '#ccc',
          });
          return btn;
        };

        const goBtn = makeBtn('Go to Library', true);
        const cancelBtn = makeBtn('Cancel', false);

        goBtn.addEventListener('click', () => {
          window.location.href = 'https://aistudio.google.com/library';
        });
        cancelBtn.addEventListener('click', () => {
          backdrop.remove();
        });

        btnRow.appendChild(goBtn);
        btnRow.appendChild(cancelBtn);
        dialog.appendChild(title);
        dialog.appendChild(msg);
        dialog.appendChild(currentPage);
        dialog.appendChild(btnRow);
        backdrop.appendChild(dialog);
        document.body.appendChild(backdrop);

        // Also close on backdrop click
        backdrop.addEventListener('click', (e) => {
          if (e.target === backdrop) backdrop.remove();
        });

        return; // stop execution
      }

      setStatus('Scanning library table...');

      // ── Scroll the table to load all rows ────────────────────────────────
      const tableWrapper = document.querySelector('div.lib-table-wrapper') ||
        document.querySelector('ms-library-table');

      if (tableWrapper && tableWrapper.scrollHeight > tableWrapper.clientHeight) {
        setStatus('Scrolling table to load all entries...');
        let lastH = -1, stable = 0;
        for (let i = 0; i < 100; i++) {
          tableWrapper.scrollTop = tableWrapper.scrollHeight;
          await sleep(CONFIG.scrollDelayMs);
          if (tableWrapper.scrollHeight === lastH) { if (++stable >= 4) break; }
          else stable = 0;
          lastH = tableWrapper.scrollHeight;
        }
        // Scroll back to top
        tableWrapper.scrollTop = 0;
        await sleep(300);
      }

      // ── Strategy 1: Extract from <table> rows ────────────────────────────
      const entries = [];
      const seenUrls = new Set();

      const tableRows = document.querySelectorAll(
        'table.library-table tr.mat-mdc-row, table.library-table tr.cdk-row'
      );

      if (tableRows.length > 0) {
        setStatus('Extracting from table...', tableRows.length + ' rows');

        tableRows.forEach((tr, idx) => {
          const cells = tr.querySelectorAll('td');
          if (cells.length < 3) return;

          // Column order: Name, Description, Type, Updated
          // Name cell contains a link
          const nameCell = tr.querySelector('td.cdk-column-name, td.mat-column-name');
          const descCell = tr.querySelector('td.cdk-column-description, td.mat-column-description');
          const typeCell = tr.querySelector('td.cdk-column-type, td.mat-column-type');
          const updatedCell = tr.querySelector('td.cdk-column-updated, td.mat-column-updated');

          const link = nameCell ? nameCell.querySelector('a[href*="/prompts/"]') : null;
          const href = link ? link.getAttribute('href') : '';
          const name = link ? link.textContent.trim() : (nameCell ? nameCell.textContent.trim() : '');
          const description = descCell ? descCell.textContent.trim() : '';
          const type = typeCell ? typeCell.textContent.trim() : '';
          const updated = updatedCell ? updatedCell.textContent.trim().replace('more_vert', '').trim() : '';

          // Get the type icon text (chat_bubble, etc.)
          const typeIcon = tr.querySelector('td .material-symbols-outlined, td mat-icon');
          const typeIconText = typeIcon ? typeIcon.textContent.trim() : '';

          const fullUrl = href ? 'https://aistudio.google.com' + href : '';

          if (name && fullUrl && !seenUrls.has(fullUrl)) {
            seenUrls.add(fullUrl);
            entries.push({
              name,
              description,
              type: type || typeIconText,
              updated,
              url: fullUrl,
              promptId: href.replace('/prompts/', ''),
            });
          }
        });
      }

      // ── Strategy 2: Fallback — extract from sidebar links ────────────────
      if (entries.length === 0) {
        setStatus('Table empty, trying sidebar links...');
        const sidebarLinks = document.querySelectorAll('a.prompt-link[href*="/prompts/"]');
        sidebarLinks.forEach(a => {
          const href = a.getAttribute('href') || '';
          const name = a.textContent.trim();
          const fullUrl = 'https://aistudio.google.com' + href;
          if (name && !seenUrls.has(fullUrl) && !href.includes('new_chat')) {
            seenUrls.add(fullUrl);
            entries.push({
              name,
              description: '',
              type: '',
              updated: '',
              url: fullUrl,
              promptId: href.replace('/prompts/', ''),
            });
          }
        });
      }

      if (entries.length === 0) {
        setStatus('⚠️ No entries found!');
        await sleep(4000); overlay.remove(); return;
      }

      setStatus('Extracted ' + entries.length + ' entries. Generating files...');

      const ts = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
      const base = 'ai_studio_library_' + ts;

      // ── JSON export ──────────────────────────────────────────────────────
      if (CONFIG.exportFormat === 'json' || CONFIG.exportFormat === 'all') {
        const jsonData = {
          exported_at: new Date().toISOString(),
          source: window.location.href,
          total_entries: entries.length,
          entries,
        };
        downloadFile(JSON.stringify(jsonData, null, 2), base + '.json', 'application/json');
      }

      // ── CSV export ───────────────────────────────────────────────────────
      if (CONFIG.exportFormat === 'csv' || CONFIG.exportFormat === 'all') {
        const escapeCsv = val => {
          const s = String(val || '');
          if (s.includes(',') || s.includes('"') || s.includes('\n')) {
            return '"' + s.replace(/"/g, '""') + '"';
          }
          return s;
        };

        const csvLines = ['Name,Description,Type,Updated,URL,Prompt ID'];
        entries.forEach(e => {
          csvLines.push([
            escapeCsv(e.name),
            escapeCsv(e.description),
            escapeCsv(e.type),
            escapeCsv(e.updated),
            escapeCsv(e.url),
            escapeCsv(e.promptId),
          ].join(','));
        });
        downloadFile(csvLines.join('\n'), base + '.csv', 'text/csv');
      }

      // ── Markdown export ──────────────────────────────────────────────────
      if (CONFIG.exportFormat === 'markdown' || CONFIG.exportFormat === 'all') {
        const md = [];
        md.push('# Google AI Studio — Library');
        md.push('');
        md.push('> Exported on ' + new Date().toISOString());
        md.push('> Total entries: ' + entries.length);
        md.push('');
        md.push('---');
        md.push('');

        // Summary table
        md.push('| # | Name | Type | Updated |');
        md.push('| --- | --- | --- | --- |');
        entries.forEach((e, i) => {
          const name = '[' + e.name.replace(/\|/g, '\\|') + '](' + e.url + ')';
          md.push('| ' + (i + 1) + ' | ' + name + ' | ' + e.type + ' | ' + e.updated + ' |');
        });
        md.push('');
        md.push('---');
        md.push('');

        // Detailed list
        md.push('## Entries');
        md.push('');
        entries.forEach((e, i) => {
          md.push('### ' + (i + 1) + '. ' + e.name);
          md.push('');
          if (e.description) md.push('> ' + e.description);
          if (e.description) md.push('');
          md.push('- **Type:** ' + (e.type || 'N/A'));
          md.push('- **Updated:** ' + (e.updated || 'N/A'));
          md.push('- **URL:** [Open in AI Studio](' + e.url + ')');
          md.push('- **Prompt ID:** `' + e.promptId + '`');
          md.push('');
          md.push('---');
          md.push('');
        });

        downloadFile(md.join('\n'), base + '.md', 'text/markdown');
      }

      // ── Summary to console ───────────────────────────────────────────────
      console.table(entries.map(e => ({ name: e.name, type: e.type, updated: e.updated, url: e.url })));

      setStatus('✅ Done! ' + entries.length + ' entries exported.', base + '.*');
      await sleep(5000);

    } catch (err) {
      setStatus('❌ ' + err.message);
      console.error('[LibExporter]', err);
      await sleep(5000);
    } finally {
      overlay.remove();
    }
  })();

// =============================================================================
// Claude.ai Chat Exporter v6 — Self-contained, API-primary, no external deps
// =============================================================================
// Run on any https://claude.ai/chat/<id> page (console paste or bookmarklet).
//
// WHAT CHANGED FROM v5 (review fixes):
//   [BLOCKING] Removed the JSZip CDN dependency entirely. claude.ai's CSP /
//              service worker blocks external <script src> loads (the v5
//              ERR_INVALID_HANDLE failure). v6 ships a tiny inline ZIP writer
//              (STORE method, no compression — no dependency, works under CSP,
//              works even when the File System Access API is unavailable).
//   [I1] Auto-scroll harvest pass materializes virtualized/off-screen turns
//        so long chats are no longer truncated to the viewport.
//   [I2] The full conversation tree from the internal API is now the PRIMARY
//        content source (it was fetched and thrown away in v5). Fiber/DOM
//        scraping is the validated fallback. DOM is merged in for image src
//        + UI timestamps.
//   [I3] Artifacts are reconstructed by folding create/rewrite/update tool_use
//        blocks, so str_replace-style edits are applied (no more stale files).
//   [I4] Artifact filenames are derived once, deterministically, and the SAME
//        name is used in the transcript refs and the written file.
//   [I5] Images are downloaded BEFORE the markdown is built, so links carry the
//        real extension (.png/.gif/.jpg) instead of a hardcoded .jpg.
//   [I6] Folder picker now runs inside the Export click (preserves the user
//        gesture); clear messaging when the FS API is unavailable.
//   [I7] Model is resolved from the API conversation + per-message data.
//   [I8] Best-effort attempt to fetch the original (non-preview) image asset.
//   [I9] Image filenames are de-duplicated to avoid overwrites.
//   [I10] Removed dead buildHtml parameter.
//   [I11] API-format max_tokens corrected to 8192.
//   [I12] markdownToHtml now handles ordered lists, blockquotes, and tables.
//   [I13] Display-only "Transcript" checkbox no longer references a missing key.
// =============================================================================

(async () => {
	"use strict";

	// ── Persistent Defaults (edit for your preferences) ──────────────────
	const CONFIG = {
		extractArtifacts: true,
		downloadImages: true,
		manifest: true,
		apiFormat: false,
		htmlOutput: true,
		stripSystemReminders: true,
		antArtifactRegex: true,
		imageConcurrency: 5,
		skipPreviouslyExported: false,
		storageMethod: "auto", // "auto" | "folder" | "zip"
	};

	// ── DOM Selectors (update here when Claude changes their UI) ──────────
	const SELECTORS = {
		scrollContainer: '[data-autoscroll-container="true"]',
		turnWrapper: "div[data-test-render-count]",
		fileThumbnail: '[data-testid="file-thumbnail"]',
		chatImage: 'img[src*="/files/"]',
		uiTimestamp: "span.text-text-500.text-xs",
	};

	const SYSTEM_REMINDER_TAGS = [
		"long_conversation_reminder",
		"userPreferences",
		"automated_reminder_from_anthropic",
		"system-reminder",
		"anthropic_reminder",
	];
	const REMINDER_REGEXES = SYSTEM_REMINDER_TAGS.map(
		(tag) => new RegExp(`<${tag}[\\s\\S]*?<\\/${tag}>`, "gi"),
	);

	const ROLE_MAP = { human: "user", assistant: "assistant" };
	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

	// ═══════════════════════════════════════════════════════════════════════
	//  INLINE ZIP WRITER (STORE / no compression) — replaces JSZip
	// ═══════════════════════════════════════════════════════════════════════
	const CRC_TABLE = (() => {
		const t = new Uint32Array(256);
		for (let n = 0; n < 256; n++) {
			let c = n;
			for (let k = 0; k < 8; k++)
				c = c & 1 ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
			t[n] = c >>> 0;
		}
		return t;
	})();

	function crc32(bytes) {
		let c = 0xffffffff;
		for (let i = 0; i < bytes.length; i++)
			c = CRC_TABLE[(c ^ bytes[i]) & 0xff] ^ (c >>> 8);
		return (c ^ 0xffffffff) >>> 0;
	}

	function dosDateTime(d) {
		const time =
			(d.getHours() << 11) |
			(d.getMinutes() << 5) |
			(d.getSeconds() >> 1);
		const date =
			((d.getFullYear() - 1980) << 9) |
			((d.getMonth() + 1) << 5) |
			d.getDate();
		return { time: time & 0xffff, date: date & 0xffff };
	}

	// files: [{ name: string, bytes: Uint8Array }]
	function buildZip(files) {
		const enc = new TextEncoder();
		const chunks = [];
		const central = [];
		let offset = 0;
		const { time, date } = dosDateTime(new Date());

		for (const f of files) {
			const nameBytes = enc.encode(f.name);
			const crc = crc32(f.bytes);
			const size = f.bytes.length;

			const lh = new Uint8Array(30 + nameBytes.length);
			const ldv = new DataView(lh.buffer);
			ldv.setUint32(0, 0x04034b50, true);
			ldv.setUint16(4, 20, true); // version needed
			ldv.setUint16(6, 0x0800, true); // flags: UTF-8 filename
			ldv.setUint16(8, 0, true); // method: STORE
			ldv.setUint16(10, time, true);
			ldv.setUint16(12, date, true);
			ldv.setUint32(14, crc, true);
			ldv.setUint32(18, size, true); // compressed size
			ldv.setUint32(22, size, true); // uncompressed size
			ldv.setUint16(26, nameBytes.length, true);
			ldv.setUint16(28, 0, true); // extra length
			lh.set(nameBytes, 30);
			chunks.push(lh, f.bytes);

			const cd = new Uint8Array(46 + nameBytes.length);
			const cdv = new DataView(cd.buffer);
			cdv.setUint32(0, 0x02014b50, true);
			cdv.setUint16(4, 20, true); // version made by
			cdv.setUint16(6, 20, true); // version needed
			cdv.setUint16(8, 0x0800, true); // flags
			cdv.setUint16(10, 0, true); // method
			cdv.setUint16(12, time, true);
			cdv.setUint16(14, date, true);
			cdv.setUint32(16, crc, true);
			cdv.setUint32(20, size, true);
			cdv.setUint32(24, size, true);
			cdv.setUint16(28, nameBytes.length, true);
			cdv.setUint16(30, 0, true); // extra
			cdv.setUint16(32, 0, true); // comment
			cdv.setUint16(34, 0, true); // disk start
			cdv.setUint16(36, 0, true); // internal attrs
			cdv.setUint32(38, 0, true); // external attrs
			cdv.setUint32(42, offset, true); // local header offset
			cd.set(nameBytes, 46);
			central.push(cd);

			offset += lh.length + size;
		}

		const cdStart = offset;
		let cdSize = 0;
		for (const c of central) {
			chunks.push(c);
			cdSize += c.length;
		}

		const eocd = new Uint8Array(22);
		const edv = new DataView(eocd.buffer);
		edv.setUint32(0, 0x06054b50, true);
		edv.setUint16(4, 0, true); // disk number
		edv.setUint16(6, 0, true); // disk with CD
		edv.setUint16(8, files.length, true);
		edv.setUint16(10, files.length, true);
		edv.setUint32(12, cdSize, true);
		edv.setUint32(16, cdStart, true);
		edv.setUint16(20, 0, true); // comment length
		chunks.push(eocd);

		let total = 0;
		for (const c of chunks) total += c.length;
		const out = new Uint8Array(total);
		let p = 0;
		for (const c of chunks) {
			out.set(c, p);
			p += c.length;
		}
		return new Blob([out], { type: "application/zip" });
	}

	async function toBytes(content) {
		if (content instanceof Blob)
			return new Uint8Array(await content.arrayBuffer());
		if (content instanceof Uint8Array) return content;
		if (content instanceof ArrayBuffer) return new Uint8Array(content);
		return new TextEncoder().encode(
			typeof content === "string" ? content : String(content),
		);
	}

